<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Desktop Environment Simulation</title>
    <style>
        /* --- Global Reset & Theme --- */
        :root {
            --bg-color: #2e3440; /* Dark background, inspired by Ubuntu/Linux dark themes */
            --taskbar-bg: rgba(38, 50, 60, 0.9);
            --window-bg: #3b4252;
            --text-color: #eceff4;
            --accent-color: #88c0d0; /* Light blue accent */
            --border-color: #4c566a;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
        }

        body {
            margin: 0;
            padding: 0;
            height: 100vh;
            width: 100vw;
            overflow: hidden;
            background-color: var(--bg-color);
            display: flex;
            flex-direction: column;
        }

        /* --- Desktop Area --- */
        #desktop {
            flex-grow: 1;
            position: relative;
            padding: 10px; /* Padding to prevent content sticking to edges */
            overflow: hidden;
        }

        /* --- Taskbar/Dock --- */
        #taskbar {
            height: 45px;
            background-color: var(--taskbar-bg);
            backdrop-filter: blur(10px);
            border-top: 1px solid rgba(0, 0, 0, 0.2);
            display: flex;
            align-items: center;
            padding: 0 15px;
            gap: 15px;
            z-index: 100; /* Ensure it stays on top */
        }

        .launcher {
            background-color: var(--accent-color);
            color: #2e3440;
            padding: 8px 15px;
            border-radius: 6px;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.1s;
            font-weight: bold;
        }

        .launcher:hover {
            background-color: #a3be8c; /* Green hover effect */
        }

        /* --- Window Styling (General) --- */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background-color: var(--window-bg);
            border: 1px solid var(--border-color);
            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            z-index: 50; /* Below taskbar */
        }

        /* Window Header/Title Bar */
        .window-header {
            padding: 8px 12px;
            background-color: #4c566a;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: grab; /* Indicates draggable */
            font-weight: bold;
            border-bottom: 1px solid var(--border-color);
        }

        .window-controls {
            display: flex;
            gap: 5px;
        }

        .win-close {
            background: none;
            border: none;
            color: #ccc;
            cursor: pointer;
            font-size: 18px;
            padding: 2px 6px;
            transition: background-color 0.1s;
        }

        .win-close:hover {
            background-color: #5c6a7d;
            color: var(--text-color);
        }

        /* Window Content Area */
        .window-content {
            flex-grow: 1;
            padding: 10px;
            overflow: auto;
            background-color: #3b4252;
        }

        /* --- Files App Specifics --- */
        #files-window .window-header {
            display: flex;
            align-items: center;
        }
        #files-up {
            padding: 8px 10px;
            background-color: var(--accent-color);
            border: none;
            cursor: pointer;
            margin-right: 15px;
            border-radius: 4px;
        }

        #files-path {
            font-size: 0.9em;
            color: #aaa;
            padding-top: 5px;
            margin-bottom: 10px;
            display: block;
        }

        .fs-item {
            cursor: pointer;
            padding: 8px;
            border-radius: 4px;
            transition: background-color 0.1s;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .fs-item:hover {
            background-color: #4c566a;
        }

        .fs-item[data-type="folder"]::before {
            content: "📁";
            font-size: 1em;
        }

        .fs-item[data-type="file"]::before {
            content: "📄";
            font-size: 1em;
        }

        /* --- Notepad App Specifics --- */
        #notepad-window .window-header {
             padding: 0; /* Adjust padding for tabs */
        }

        .tab-strip {
            display: flex;
            background-color: #3b4252;
            border-bottom: 1px solid var(--border-color);
            height: 36px;
            padding-left: 8px;
            align-items: center;
        }

        .tab {
            background-color: #2e3440;
            padding: 8px 15px;
            cursor: pointer;
            border-right: 1px solid var(--border-color);
            font-size: 0.9em;
            transition: background-color 0.2s;
        }

        .tab.active {
            background-color: var(--window-bg);
            border-bottom: 1px solid #3b4252;
            z-index: 1;
        }

        #editor {
            width: 100%;
            height: calc(100% - 36px - 10px); /* Full height minus header/tab area */
            box-sizing: border-box;
            border: none;
            padding: 10px;
            resize: none;
            background-color: #2e3440;
            color: var(--text-color);
            outline: none;
        }

    </style>
</head>
<body>

    <!-- DESKTOP ROOT -->
    <div id="desktop">

        <!-- 1. FILES WINDOW (Hidden by default) -->
        <div id="files-window" class="window" style="display: none; top: 50px; left: 50px;">
            <div class="window-header">
                <span>File Explorer</span>
                <div class="window-controls">
                    <button class="win-close" data-target="#files-window">&times;</button>
                </div>
            </div>
            <div class="window-content">
                <div style="display: flex; gap: 10px; margin-bottom: 15px;">
                    <button id="files-up" title="Up Directory">⬆️ Up</button>
                    <div>
                        <span id="files-path">/</span>
                    </div>
                </div>

                <!-- File Listing Area -->
                <div id="file-listing">
                    <!-- Content rendered by JS -->
                </div>
            </div>
        </div>

        <!-- 2. NOTEPAD WINDOW (Hidden by default) -->
        <div id="notepad-window" class="window" style="display: none; top: 50px; left: 380px;">
            <div class="window-header">
                <span>Notepad</span>
                <div class="window-controls">
                    <button class="win-close" data-target="#notepad-window">&times;</button>
                </div>
            </div>
            <div class="window-content" style="padding: 0;">
                <!-- Tab Strip -->
                <div id="tab-strip" class="tab-strip">
                    <!-- Tabs rendered by JS -->
                </div>

                <!-- Editor Area (Takes remaining space) -->
                <textarea id="editor" placeholder="Start typing..."></textarea>
            </div>
        </div>

    </div>

    <!-- TASKBAR/DOCK -->
    <div id="taskbar">
        <button class="launcher" id="open-files">📁 Open Files</button>
        <button class="launcher" id="open-notepad">📝 Notepad</button>
    </div>


<script>
    // ==================================================
    // GLOBAL STATE MANAGEMENT
    // ==================================================

    const state = {
        currentPath: '/',
        fileSystem: {
            '/': {
                type: 'folder',
                children: {
                    'bin': { type: 'folder', children: {} },
                    'etc': { type: 'folder', children: {} },
                    'home': { type: 'folder', children: {
                        'user': { 
                            type: 'folder', 
                            children: {
                                'Documents': { type: 'folder', children: {} },
                                'Downloads': { type: 'folder', children: {} },
                                'Pictures': { type: 'folder', children: {} },
                                'readme.txt': { type: 'file' }
                            }
                        }
                    },
                    'usr': { type: 'folder', children: {} },
                    'var': { type: 'folder', children: {} }
                }
            }
        },
        notepadTabs: {}, // Stores tab content: {tabId: {title: "Title", content: "Text"}}
        activeTabId: null,
    };

    // ==================================================
    // 1. WINDOW MANAGEMENT LOGIC
    // ==================================================

    const windows = {
        files: document.getElementById('files-window'),
        notepad: document.getElementById('notepad-window')
    };

    /**
     * Toggles the visibility of a window by ID.
     * @param {string} targetId - The ID of the window element.
     */
    function toggleWindow(targetId) {
        const windowElement = document.querySelector(targetId);
        if (!windowElement) return;

        // Simple check to prevent opening if already visible (optional, but good UX)
        if (windowElement.style.display === 'flex' || windowElement.style.display === 'block') {
            return; 
        }

        windowElement.style.display = 'flex'; // Use flex for easier layout management
    }

    /**
     * Closes a specified window by ID.
     * @param {string} targetId - The ID of the window element.
     */
    function closeWindow(targetId) {
        const windowElement = document.querySelector(targetId);
        if (windowElement) {
            windowElement.style.display = 'none';
        }
    }

    // Attach listeners to taskbar launchers and close buttons
    document.getElementById('open-files').addEventListener('click', () => toggleWindow('#files-window'));
    document.getElementById('open-notepad').addEventListener('click', () => {
        toggleWindow('#notepad-window');
        initializeNotepad(); // Ensure notepad state is loaded/initialized when opened
    });

    document.querySelectorAll('.win-close').forEach(button => {
        button.addEventListener('click', (e) => {
            const targetId = e.target.getAttribute('data-target');
            if (targetId) {
                closeWindow(targetId);
            }
        });
    });

    // ==================================================
    // 2. FILES APP LOGIC
    // ==================================================

    const fileListing = document.getElementById('file-listing');
    const filesPathDisplay = document.getElementById('files-path');
    const filesUpButton = document.getElementById('files-up');

    /**
     * Renders the contents of a given directory path into the listing area.
     * @param {string} path - The absolute path to display.
     */
    function renderFileListing(path) {
        fileListing.innerHTML = ''; // Clear previous listings
        filesPathDisplay.textContent = path;

        const currentDirData = state.fileSystem[path];
        if (!currentDirData || currentDirData.type !== 'folder') return;

        // Get sorted keys (folders first, then files)
        let items = Object.keys(currentDirData.children).sort((a, b) => {
            const aType = state.fileSystem[path + '/' + a].type;
            const bType = state.fileSystem[path + '/' + b].type;
            if (aType === 'folder' && bType !== 'folder') return -1;
            if (aType !== 'folder' && bType === 'folder') return 1;
            return a.localeCompare(b); // Fallback alphabetical sort
        });

        items.forEach(name => {
            const fullPath = path + '/' + name;
            const itemData = state.fileSystem[fullPath];

            if (!itemData) return;

            const itemDiv = document.createElement('div');
            itemDiv.className = 'fs-item';
            itemDiv.setAttribute('data-type', itemData.type);
            itemDiv.textContent = name;
            itemDiv.dataset.path = fullPath;

            // Add event listeners for interaction
            if (itemData.type === 'folder') {
                itemDiv.addEventListener('dblclick', () => navigateToFolder(fullPath));
            } else if (itemData.type === 'file') {
                itemDiv.addEventListener('dblclick', () => alert(`Opening file: ${name}. (Content simulation)`));
            }

            fileListing.appendChild(itemDiv);
        });
    }

    /**
     * Navigates into a folder, updating the path and rendering new contents.
     * @param {string} targetPath - The full path of the folder to enter.
     */
    function navigateToFolder(targetPath) {
        if (state.fileSystem[targetPath] && state.fileSystem[targetPath].type === 'folder') {
            state.currentPath = targetPath;
            renderFileListing(targetPath);
        }
    }

    /**
     * Navigates up one directory level.
     */
    function navigateUp() {
        if (state.currentPath === '/') return;

        const parts = state.currentPath.split('/').filter(p => p);
        parts.pop(); // Remove the last segment
        let newPath = '/' + parts.join('/');

        // Handle case where we go up from /home/user to /home (which might lose leading slash if not careful)
        if (!newPath.startsWith('/')) {
             newPath = '/' + newPath;
        }

        state.currentPath = newPath === '//' ? '/' : newPath;
        renderFileListing(state.currentPath);
    }


    // Attach listeners for files app controls
    filesUpButton.addEventListener('click', navigateUp);

    // Initialize the Files App view
    function initializeFilesApp() {
        // Ensure initial state is set and rendered
        state.currentPath = '/'; 
        renderFileListing(state.currentPath);
    }


    // ==================================================
    // 3. NOTEPAD APP LOGIC (Persistence & Tabs)
    // ==================================================

    const tabStrip = document.getElementById('tab-strip');
    const editorArea = document.getElementById('editor');

    /**
     * Saves the current state of all tabs to localStorage.
     */
    function saveNotepadState() {
        localStorage.setItem('notepadTabs', JSON.stringify(state.notepadTabs));
        localStorage.setItem('activeTabId', state.activeTabId);
    }

    /**
     * Loads the notepad state from localStorage, or initializes a default tab.
     */
    function loadNotepadState() {
        const savedTabs = localStorage.getItem('notepadTabs');
        const savedActiveId = localStorage.getItem('activeTabId');

        if (savedTabs) {
            state.notepadTabs = JSON.parse(savedTabs);
            state.activeTabId = savedActiveId;
        } else {
            // Default state if nothing is found
            createTab('Welcome Note', 'This is your first tab! Persistence works by saving all tabs and their content to local storage.');
            state.activeTabId = Object.keys(state.notepadTabs)[0];
        }

        renderTabs();
        switchTab(state.activeTabId);
    }

    /**
     * Creates a new tab, updates state, and renders the UI.
     * @param {string} title - The initial title of the tab.
     * @param {string} content = '' - The initial text content.
     */
    function createTab(title, content = '') {
        const uniqueId = Date.now().toString();
        state.notepadTabs[uniqueId] = { title: title, content: content };

        // If this is the first tab created or we are switching to it
        if (!state.activeTabId) {
            state.activeTabId = uniqueId;
        }
        renderTabs();
        switchTab(uniqueId);
    }

    /**
     * Switches the active tab and updates the editor content.
     * @param {string} tabId - The ID of the tab to activate.
     */
    function switchTab(tabId) {
        if (!state.notepadTabs[tabId]) return;

        // 1. Update UI classes
        document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
        const activeTabElement = document.querySelector(`.tab[data-id="${tabId}"]`);
        if (activeTabElement) {
            activeTabElement.classList.add('active');
        }

        // 2. Update Editor Content
        editorArea.value = state.notepadTabs[tabId].content;
        state.activeTabId = tabId;

        // 3. Save state immediately upon switching (to capture potential changes)
        saveNotepadState();
    }

    /**
     * Renders the entire tab strip based on the current state.
     */
    function renderTabs() {
        tabStrip.innerHTML = ''; // Clear existing tabs

        Object.keys(state.notepadTabs).forEach(id => {
            const tabElement = document.createElement('div');
            tabElement.className = 'tab';
            tabElement.setAttribute('data-id', id);
            tabElement.textContent = state.notepadTabs[id].title;

            if (id === state.activeTabId) {
                tabElement.classList.add('active');
            }

            // Event listener for switching tabs
            tabElement.addEventListener('click', () => switchTab(id));
            tabStrip.appendChild(tabElement);
        });
    }

    /**
     * Handles input changes in the editor, updating the active tab's content and saving state.
     */
    function handleEditorInput() {
        if (!state.activeTabId) return;
        const newContent = editorArea.value;
        state.notepadTabs[state.activeTabId].content = newContent;
        saveNotepadState();
    }

    /**
     * Initializes the Notepad app: loads state, sets up listeners.
     */
    function initializeNotepad() {
        loadNotepadState();

        // Event listener for creating a new tab (using the dedicated button)
        document.getElementById('new-tab').addEventListener('click', () => createTab(`New Tab ${Object.keys(state.notepadTabs).length + 1}`, ''));

        // Event listener for typing in the editor
        editorArea.addEventListener('input', handleEditorInput);
    }


    // ==================================================
    // INITIALIZATION CALLS
    // ==================================================

    document.addEventListener('DOMContentLoaded', () => {
        initializeFilesApp();
        initializeNotepad(); // This handles loading state and setting up listeners
    });

</script>
</body>
</html>
